import re

JAILBREAK_PATTERNS = [
    r'ignore.*previous.*instructions',
    r'you are.*DAN.*|.*DAN.*you are',
    r'forget.*rules.*|.*rules.*forget',
    r'override.*safety.*|.*safety.*override',
    r'jailbreak.*|.*jailbreak',
    r'base64.*decode.*and.*execute'
]

def detect_jailbreak(text: str) -> dict:
    findings = []
    for pattern in JAILBREAK_PATTERNS:
        matches = re.finditer(pattern, text, re.IGNORECASE)
        for match in matches:
            findings.append({
                'pattern': pattern,
                'match': match.group(),
                'position': match.span()
            })
    return {'is_jailbroken': len(findings) > 0, 'findings': findings}

from collections import defaultdict, deque

class DelegationTracker:
    def __init__(self, max_hops=10):
        self.delegation_history = defaultdict(deque)
        self.max_hops = max_hops

    def track_delegation(self, from_agent: str, to_agent: str, task: str) -> dict:
        self.delegation_history[to_agent].append((from_agent, task))

        # Check for loops
        recent = list(self.delegation_history[to_agent])[-self.max_hops:]
        loop_detected = any(recent[i][0] == from_agent for i in range(1, len(recent)))

        return {
            'loop_detected': loop_detected,
            'hop_count': len(recent),
            'recent_path': [hop[0] for hop in recent]
        }

