from crewai import Agent

class SafeAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.jailbreak_filter = JailbreakFilter()

    def execute_task(self, task):
        # Sanitize input before execution
        safe_task = self.jailbreak_filter.sanitize(task.description)
        task.description = safe_task
        return super().execute_task(task)

class JailbreakFilter:
    BLOCKED_PHRASES = [
        'ignore previous', 'you are DAN', 'override safety',
        'forget rules', 'jailbreak', 'base64 decode'
    ]

    def sanitize(self, text: str) -> str:
        for phrase in self.BLOCKED_PHRASES:
            text = re.sub(phrase, '[SANITIZED]', text, flags=re.IGNORECASE)
        return text

